func Download(ctx context.Context, url string, target io.Writer, options ...DownloadOption) (err error) {
	opts := downloadOptions{
		stalenessTimeout: time.Minute,
		header:           http.Header{},
	}
	for _, opt := range options {
		opt(&opts)
	}

	// this transports is, by design, a trimmed down version of http's
	// DefaultTransport. we do not want to have all those timeouts the
	// default client brings in.
	transport := &http.Transport{
		// This is a one-shot HTTP client which should release resources immediately.
		DisableKeepAlives: true,
		Proxy:             http.ProxyFromEnvironment,
	}

	// if tls check is disabled, we need to disable the transport's TLS checks as well.
	if opts.insecureSkipTLSVerify {
		transport.TLSClientConfig = &tls.Config{InsecureSkipVerify: true}
	}

	// Prepare the client and the request.
	client := http.Client{Transport: transport}
	req, err := http.NewRequest(http.MethodGet, url, nil)
	if err != nil {
		return fmt.Errorf("invalid download request: %w", err)
	}
	req.Header.Set("User-Agent", "k0s/"+build.Version)
	for header, values := range opts.header {
		for _, value := range values {
			req.Header.Add(header, value)
		}
	}

	if opts.username != "" && opts.password != "" {
		req.SetBasicAuth(opts.username, opts.password)
	}

	// Create a context with an inactivity timeout to cancel the download if it stalls.
	ctx, cancel, keepAlive := k0scontext.WithInactivityTimeout(ctx, opts.stalenessTimeout)
	defer cancel(nil)

	// Execute the request.
	resp, err := client.Do(req.WithContext(ctx))
	if err != nil {
		return fmt.Errorf("request failed: %w", err)
	}
	defer func() {
		if closeErr := resp.Body.Close(); closeErr != nil {
			err = errors.Join(err, closeErr)
		}
	}()

	if resp.StatusCode != http.StatusOK {
		return fmt.Errorf("bad status: %s", resp.Status)
	}

	if err := opts.detectRemoteFileName(resp); err != nil {
		return err
	}

	// Monitor writes. Keep the download context alive as long as data is flowing.
	writeMonitor := internalio.WriterFunc(func(p []byte) (int, error) {
		len := len(p)
		if len > 0 {
			keepAlive()
		}
		return len, nil
	})

	// Run the actual data transfer.
	if _, err := io.Copy(io.MultiWriter(writeMonitor, target), resp.Body); err != nil {
		return fmt.Errorf("while downloading: %w", err)
	}

	return nil
}

func (c *CertificateManager) loadFromFilesystem() error {

	raw, err := os.ReadFile(c.config.CertFile)
	if err != nil {
		return fmt.Errorf("can't hash certificate: %w", err)
	}
	newHash := fmt.Sprintf("%x", md5.Sum(raw))

	if newHash == c.currentHash {
		return nil
	}

	cert, err := tls.LoadX509KeyPair(c.config.CertFile, c.config.KeyFile)
	if err != nil {
		return fmt.Errorf("can't load key pair: %w", err)
	}

	// the code borrowed from kubelet assumes Leaf is loaded which does not happen via tls.LoadX509KeyPair...
	cert.Leaf, err = x509.ParseCertificate(cert.Certificate[0])
	if err != nil {
		return fmt.Errorf("can't parse certificate: %w", err)
	}
	c.currentHash = newHash
	c.currentCertificate = &cert

	return nil
}

func isPre1_27ManagedConfig(path string) (bool, error) {
	// Check MD5 sum of the config file
	// If it matches the pre 1.27 config, it's k0s managed
	md5sum := md5.New()
	f, err := os.Open(path)
	if err != nil {
		return false, err
	}
	defer f.Close()

	if _, err := io.Copy(md5sum, f); err != nil {
		return false, err
	}

	sum := md5sum.Sum(nil)

	pre1_27ConfigSumBytes, err := hex.DecodeString(pre1_27ConfigSum)
	if err != nil {
		return false, err
	}

	if bytes.Equal(pre1_27ConfigSumBytes, sum) {
		return true, nil
	}

	return false, nil
}

func resourceChecksum(resource *unstructured.Unstructured) string {
	json, err := resource.MarshalJSON()
	if err != nil {
		return ""
	}
	hasher := md5.New()
	// based on the implementation hasher.Write never returns err
	_, _ = hasher.Write(json)

	return hex.EncodeToString(hasher.Sum(nil))
}

func (m *Manager) CreateKeyPair(name string, k0sVars *config.CfgVars, ownerID int) error {
	keyFile := filepath.Join(k0sVars.CertRootDir, name+".key")
	pubFile := filepath.Join(k0sVars.CertRootDir, name+".pub")

	if file.Exists(keyFile) && file.Exists(pubFile) {
		return file.Chown(keyFile, ownerID, constant.CertSecureMode)
	}

	reader := rand.Reader
	bitSize := 2048

	key, err := rsa.GenerateKey(reader, bitSize)
	if err != nil {
		return err
	}

	err = file.WriteAtomically(keyFile, constant.CertSecureMode, func(unbuffered io.Writer) error {
		privateKey := pem.Block{
			Type:  "RSA PRIVATE KEY",
			Bytes: x509.MarshalPKCS1PrivateKey(key),
		}

		w := bufio.NewWriter(unbuffered)
		if err := pem.Encode(w, &privateKey); err != nil {
			return err
		}
		return w.Flush()
	})

	if err != nil {
		return err
	}

	return file.WriteAtomically(pubFile, 0644, func(unbuffered io.Writer) error {
		// note to the next reader: key.Public() != key.PublicKey
		pubBytes, err := x509.MarshalPKIXPublicKey(key.Public())
		if err != nil {
			return err
		}

		pemKey := pem.Block{
			Type:  "PUBLIC KEY",
			Bytes: pubBytes,
		}

		w := bufio.NewWriter(unbuffered)
		if err := pem.Encode(w, &pemKey); err != nil {
			return err
		}
		return w.Flush()
	})
}

func hash(data []byte) string {
	return fmt.Sprintf("%x", md5.Sum(data))
}

func getClient(certFile, keyFile string) (*http.Client, error) {
	transport := http.DefaultTransport.(*http.Transport).Clone()
	transport.ResponseHeaderTimeout = time.Minute
	tlsConfig := &tls.Config{InsecureSkipVerify: true}
	transport.TLSClientConfig = tlsConfig

	if certFile != "" && keyFile != "" {
		cert, err := tls.LoadX509KeyPair(certFile, keyFile)
		if err != nil {
			return nil, err
		}
		tlsConfig.Certificates = []tls.Certificate{cert}
	}
	return &http.Client{
		Transport: transport,
		Timeout:   time.Minute,
	}, nil
}

func Download(ctx context.Context, url string, target io.Writer, options ...DownloadOption) (err error) {
	opts := downloadOptions{}
	for _, opt := range options {
		opt(&opts)
	}

	creds, err := opts.auth.CredentialStore(ctx)
	if err != nil {
		return fmt.Errorf("failed to create credential store: %w", err)
	}

	imgref, err := registry.ParseReference(url)
	if err != nil {
		return fmt.Errorf("failed to parse artifact reference: %w", err)
	}

	repo, err := remote.NewRepository(url)
	if err != nil {
		return fmt.Errorf("failed to create repository: %w", err)
	}

	if opts.plainHTTP {
		repo.PlainHTTP = true
	}

	transp := http.DefaultTransport.(*http.Transport).Clone()
	if opts.insecureSkipTLSVerify {
		transp.TLSClientConfig = &tls.Config{InsecureSkipVerify: true}
	}

	repo.Client = &auth.Client{
		Client:     &http.Client{Transport: transp},
		Credential: creds.Get,
	}

	tag := imgref.Reference
	successors, err := fetchSuccessors(ctx, repo.Manifests(), tag)
	if err != nil {
		return fmt.Errorf("failed to fetch successors: %w", err)
	}

	source, err := findArtifactDescriptor(successors, opts)
	if err != nil {
		return fmt.Errorf("failed to find artifact: %w", err)
	}

	// Get a reader to the blob.
	raw, err := repo.Blobs().Fetch(ctx, source)
	if err != nil {
		return fmt.Errorf("failed to fetch blob: %w", err)
	}
	defer func() { err = errors.Join(err, raw.Close()) }()

	// Wrap the reader so that its length and digest will be verified.
	verified := content.NewVerifyReader(raw, source)

	// Copy over the blob to its target.
	if _, err := io.Copy(target, verified); err != nil {
		return fmt.Errorf("failed to copy blob: %w", err)
	}

	// Verify the digest.
	return verified.Verify()
}

func (s *BootlooseSuite) WaitJoinAPI(node string) error {
	s.T().Logf("Waiting for k0s join API to start on node %s", node)

	m, err := s.MachineForName(node)
	if err != nil {
		return err
	}
	joinPort, err := m.HostPort(s.K0sAPIExternalPort)
	if err != nil {
		return err
	}
	client := &http.Client{Transport: &http.Transport{
		TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
	}}
	checkURL := fmt.Sprintf("https://localhost:%d/v1beta1/ca", joinPort)

	return Poll(s.Context(), func(context.Context) (done bool, err error) {
		resp, err := client.Get(checkURL)
		if err != nil {
			return false, nil
		}
		defer resp.Body.Close()

		// JoinAPI returns always un-authorized when called with no token, but it's a signal that it properly up-and-running still
		if resp.StatusCode != http.StatusUnauthorized {
			return false, nil
		}

		s.T().Logf("K0s join API up-and-running")
		return true, nil
	})
}

func (c *SSHConnection) Connect(ctx context.Context) error {
	key, err := loadExternalFile(c.KeyPath)
	if err != nil {
		return err
	}

	config := &ssh.ClientConfig{
		User:            c.User,
		HostKeyCallback: ssh.InsecureIgnoreHostKey(),
	}
	address := fmt.Sprintf("%s:%d", c.Address, c.Port)

	sshAgentSock := os.Getenv("SSH_AUTH_SOCK")
	signer, err := ssh.ParsePrivateKey(key)
	if err != nil && sshAgentSock == "" {
		return err
	}
	if err == nil {
		config.Auth = append(config.Auth, ssh.PublicKeys(signer))
	}

	// https://github.com/golang/go/issues/20288#issuecomment-707078634
	d := net.Dialer{Timeout: config.Timeout}
	netConn, err := d.DialContext(ctx, "tcp", address)
	if err != nil {
		return err
	}
	conn, chans, reqs, err := ssh.NewClientConn(netConn, address, config)
	if err != nil {
		return err
	}
	c.client = ssh.NewClient(conn, chans, reqs)

	return nil
}
